CalculateField C:\GISstresstesten\Panden1702\Run51702.gdb\KPI_Pand_Rekengrens Risicoscore calculate_risicoscore(!A_procent_gevel_water!, !B_lengte_gevel_water!, !C_max_hoogte_gevel_water!) Python "
def calculate_risicoscore(A, B, C):
    average = round((A + B + C) / 3, 2)     # afronden op 2 decimalen
    if A == 1 or B == 1 or C == 1:  
        return min(average, 2)              # als één van de parameters 1 is, wordt maximaal 2 (laag risico) teruggegeven
    else:  
        return average
" Text NO_ENFORCE_DOMAINS

