def calculate_risicoscore_cat(x):
    if x < 1.5:
        return "Geen Risico"
    elif 1.5 <= x < 2.5:
        return "Laag Risico"
    elif 2.5 <= x < 3.5:
        return "Middel Risico"
    else:  # x >= 3.5
        return "Hoog Risico"
" Text NO_ENFORCE_DOMAINS

