def calculate_pandlevel(A, B, C, x):
    average = round((A + B + C) / 3, 2)     # afronden op 2 decimalen
    if x < 0:
        return -1
    elif x > 0:
        return 5
    elif A == 1 or B == 1 or C == 1:  
        return min(average, 2)              # als één van de parameters 1 is, wordt maximaal 2 (laag risico) teruggegeven
    else:  
        return average
" Text NO_ENFORCE_DOMAINS

