def def_pandlevel(x):
    if x < 0:
        return "Pand onder maaiveld"
    elif x < 1.5:
        return "Geen Risico"
    elif 1.5 <= x < 2.5:
        return "Laag Risico"
    elif 2.5 <= x < 3.5:
        return "Middel Risico"
    elif 3.5 <= x < 5:
        return "Hoog Risico"
    else: # x >= 5
        return "Pand boven maaiveld"
